import React, { Component } from "react";
import "./App.css";
import Image1 from "../src/images/jaja2.jpg";
import Image2 from "../src/images/photo2.jpg";

class Slider extends Component {
  constructor(props) {
    super(props);
    this.state = {
      number: 0,
      listOfImages: [Image1, Image2],
    };
  }

  /*cycle = () => {
    if (this.state.number != this.state.listOfImages.length - 1) {
      this.setState({ number: this.state.number + 1 });
    } else {
      this.setState({ number: 0 });
    }
  };*/

  cycle2 = () => {
    setInterval(() => {
      this.setState({ number: this.state.number + 1 });
      if (this.state.number === this.state.listOfImages.length - 1) {
        this.setState({ number: 0 });
      }
    }, 8000);
  };

  /*componentDidMount() {
    setTimeout(() => {
      if (this.state.number === 0) {
        this.setState({ number: 1 });
      } else {
        this.setState({ number: 0 });
      }
    }, 5000);
  }*/
  render() {
    //setInterval(this.cycle, 5000);
    return (
      <div className="divSlider">
        <img
          className="photo1"
          src={this.state.listOfImages[this.state.number]}
          alt="programmingPhoto1"
        />
      </div>
    );
  }
}
